import{_ as a,c as i,a0 as t,o as c}from"./chunks/framework.B6JXc2q-.js";const u=JSON.parse('{"title":"WebUI 架构（WebUI Architecture）","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/webui_architecture.md","filePath":"architecture/webui_architecture.md"}'),o={name:"architecture/webui_architecture.md"};function d(l,e,s,r,p,n){return c(),i("div",null,e[0]||(e[0]=[t('<h1 id="webui-架构-webui-architecture" tabindex="-1">WebUI 架构（WebUI Architecture） <a class="header-anchor" href="#webui-架构-webui-architecture" aria-label="Permalink to &quot;WebUI 架构（WebUI Architecture）&quot;">​</a></h1><p>版本：v1.0 状态：正式架构文档 最后更新：2026-03-28</p><p>本文档定义 WebUI 与后端的接口依赖边界、状态来源模型与禁止依赖范围。具体状态字段语义见 <code>docs/spec/player_state_projection_spec.md</code>，SSE 协议见 <code>docs/spec/player_stream_sse_spec.md</code>，API 契约见 <code>docs/api/api_v1_spec.md</code>。</p><hr><h2 id="_1-webui-依赖的接口层" tabindex="-1">1. WebUI 依赖的接口层 <a class="header-anchor" href="#_1-webui-依赖的接口层" aria-label="Permalink to &quot;1. WebUI 依赖的接口层&quot;">​</a></h2><p>WebUI 只允许依赖以下两个接口层：</p><h3 id="_1-1-public-api-api-v1" tabindex="-1">1.1 Public API（<code>/api/v1/*</code>） <a class="header-anchor" href="#_1-1-public-api-api-v1" aria-label="Permalink to &quot;1.1 Public API（`/api/v1/*`）&quot;">​</a></h3><p>所有 <code>docs/api/api_v1_spec.md</code> 白名单中的接口。WebUI、Home Assistant、第三方调用方均可使用。</p><p>WebUI 当前使用的 Public API：</p><ul><li><code>GET /api/v1/player/stream</code>（<strong>SSE 主通道</strong>，播放状态）</li><li><code>GET /api/v1/player/state</code>（初始化 + 降级 fallback）</li><li><code>GET /api/v1/devices</code></li><li><code>GET /api/v1/library/playlists</code></li><li><code>GET /api/v1/system/status</code></li><li><code>GET /api/v1/system/settings</code></li><li><code>POST /api/v1/system/settings</code></li><li><code>POST /api/v1/system/settings/item</code></li><li><code>POST /api/v1/play</code></li><li><code>POST /api/v1/control/*</code>（stop、pause、resume、next、previous 等）</li><li><code>GET /api/v1/search/online</code></li></ul><h3 id="_1-2-internal-api-api-auth-、-api-file" tabindex="-1">1.2 Internal API（<code>/api/auth/*</code>、<code>/api/file/*</code>） <a class="header-anchor" href="#_1-2-internal-api-api-auth-、-api-file" aria-label="Permalink to &quot;1.2 Internal API（`/api/auth/*`、`/api/file/*`）&quot;">​</a></h3><p>仅供 WebUI 使用，不对外承诺兼容性：</p><ul><li><code>GET /api/auth/status</code></li><li><code>POST /api/auth/refresh</code></li><li><code>POST /api/auth/logout</code></li><li><code>GET /api/get_qrcode</code></li><li><code>POST /api/file/fetch_playlist_json</code></li><li><code>POST /api/file/cleantempdir</code></li></ul><hr><h2 id="_2-webui-的播放状态来源" tabindex="-1">2. WebUI 的播放状态来源 <a class="header-anchor" href="#_2-webui-的播放状态来源" aria-label="Permalink to &quot;2. WebUI 的播放状态来源&quot;">​</a></h2><p>WebUI 的播放状态由后端唯一决定。前端只消费，不裁决。</p><h3 id="_2-1-主通道-sse" tabindex="-1">2.1 主通道：SSE <a class="header-anchor" href="#_2-1-主通道-sse" aria-label="Permalink to &quot;2.1 主通道：SSE&quot;">​</a></h3><p><code>GET /api/v1/player/stream</code> 是播放状态的主通道。WebUI 必须在 SSE 连接正常时以 SSE 事件作为唯一状态来源，不得同时轮询 <code>/player/state</code>。</p><h3 id="_2-2-初始化-降级通道-http" tabindex="-1">2.2 初始化 + 降级通道：HTTP <a class="header-anchor" href="#_2-2-初始化-降级通道-http" aria-label="Permalink to &quot;2.2 初始化 + 降级通道：HTTP&quot;">​</a></h3><p><code>GET /api/v1/player/state</code> 用于：</p><ul><li>页面首次加载时获取初始快照</li><li>SSE 断线期间的降级轮询（间隔 ≥ 3s）</li></ul><p>SSE 重连成功后，必须立即停止轮询。</p><h3 id="_2-3-状态消费模型" tabindex="-1">2.3 状态消费模型 <a class="header-anchor" href="#_2-3-状态消费模型" aria-label="Permalink to &quot;2.3 状态消费模型&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>serverState（来自 SSE / HTTP，只读）</span></span>\n<span class="line"><span>    ↓</span></span>\n<span class="line"><span>revision gate（去重过滤）</span></span>\n<span class="line"><span>    ↓</span></span>\n<span class="line"><span>session switch handler（play_session_id 变化 → 全 UI 切换）</span></span>\n<span class="line"><span>    ↓</span></span>\n<span class="line"><span>render（基于 transport_state / track.id / position_ms 等字段）</span></span></code></pre></div><p>前端维护的 <code>uiState</code> 只包含纯展示辅助状态（连接状态、切歌动画标记、进度插值），不代表任何播放事实。</p><p>完整消费规则见 <code>docs/spec/webui_playback_state_machine_spec.md</code>。</p><hr><h2 id="_3-webui-不允许依赖的内容" tabindex="-1">3. WebUI 不允许依赖的内容 <a class="header-anchor" href="#_3-webui-不允许依赖的内容" aria-label="Permalink to &quot;3. WebUI 不允许依赖的内容&quot;">​</a></h2><p>以下内容明确禁止 WebUI 依赖：</p><h3 id="_3-1-后端内部对象" tabindex="-1">3.1 后端内部对象 <a class="header-anchor" href="#_3-1-后端内部对象" aria-label="Permalink to &quot;3.1 后端内部对象&quot;">​</a></h3><ul><li><code>XiaoMusic</code> 实例或其任何属性</li><li><code>DevicePlayer</code> 实例</li><li><code>PlaybackFacade</code> 内部状态</li><li><code>PlaybackCoordinator</code> 内部状态</li><li><code>SourceRegistry</code> 或任何 source 插件实现</li></ul><h3 id="_3-2-未承诺的-api-字段" tabindex="-1">3.2 未承诺的 API 字段 <a class="header-anchor" href="#_3-2-未承诺的-api-字段" aria-label="Permalink to &quot;3.2 未承诺的 API 字段&quot;">​</a></h3><ul><li><code>api_v1_spec.md</code> 白名单接口中未声明的 <code>data</code> 字段</li><li>通过观察实现行为&quot;发现&quot;但未在规范中列出的字段</li><li><code>docs/api/api_v1_spec.md</code> 第 13 章列出的兼容字段（<code>cur_music</code>、<code>is_playing</code>、<code>offset</code>、<code>duration</code> 等）——这些字段已废弃，新代码不得读取</li></ul><h3 id="_3-3-内部-api-路由" tabindex="-1">3.3 内部 API 路由 <a class="header-anchor" href="#_3-3-内部-api-路由" aria-label="Permalink to &quot;3.3 内部 API 路由&quot;">​</a></h3><ul><li>任何未列入 <code>api_v1_spec.md</code> 白名单且未列入 Internal API 清单的路由</li><li><code>Forbidden / Removed</code> 分类中的接口</li></ul><h3 id="_3-4-websocket-状态推送" tabindex="-1">3.4 WebSocket 状态推送 <a class="header-anchor" href="#_3-4-websocket-状态推送" aria-label="Permalink to &quot;3.4 WebSocket 状态推送&quot;">​</a></h3><p>系统当前不提供 WebSocket 状态推送。历史讨论过的 WebSocket 方案已废弃，不得在新实现中引入。状态推送统一通过 SSE（<code>GET /api/v1/player/stream</code>）实现。</p><hr><h2 id="_4-webui-与各后端能力的关系" tabindex="-1">4. WebUI 与各后端能力的关系 <a class="header-anchor" href="#_4-webui-与各后端能力的关系" aria-label="Permalink to &quot;4. WebUI 与各后端能力的关系&quot;">​</a></h2><h3 id="_4-1-播放器状态" tabindex="-1">4.1 播放器状态 <a class="header-anchor" href="#_4-1-播放器状态" aria-label="Permalink to &quot;4.1 播放器状态&quot;">​</a></h3><ul><li>来源：<code>GET /api/v1/player/stream</code>（主）/ <code>GET /api/v1/player/state</code>（备）</li><li>字段模型：<code>docs/spec/player_state_projection_spec.md</code></li><li>前端不得以本地推算覆盖服务端状态</li></ul><h3 id="_4-2-系统状态与设置" tabindex="-1">4.2 系统状态与设置 <a class="header-anchor" href="#_4-2-系统状态与设置" aria-label="Permalink to &quot;4.2 系统状态与设置&quot;">​</a></h3><ul><li>来源：<code>GET /api/v1/system/status</code>、<code>GET /api/v1/system/settings</code></li><li>设置修改通过：<code>POST /api/v1/system/settings</code>、<code>POST /api/v1/system/settings/item</code></li></ul><h3 id="_4-3-歌单与音乐库" tabindex="-1">4.3 歌单与音乐库 <a class="header-anchor" href="#_4-3-歌单与音乐库" aria-label="Permalink to &quot;4.3 歌单与音乐库&quot;">​</a></h3><ul><li>来源：<code>GET /api/v1/library/playlists</code></li><li>每个歌曲条目包含 <code>id</code>（稳定标识）和 <code>title</code>（展示名）</li><li>歌单选中项同步必须基于 <code>track.id</code> 对照，不得依赖 <code>title</code> 文本匹配</li></ul><h3 id="_4-4-认证状态" tabindex="-1">4.4 认证状态 <a class="header-anchor" href="#_4-4-认证状态" aria-label="Permalink to &quot;4.4 认证状态&quot;">​</a></h3><ul><li>来源：<code>GET /api/auth/status</code>（Internal API）</li><li>刷新：<code>POST /api/auth/refresh</code></li></ul><hr><h2 id="_5-接口变更时的影响评估" tabindex="-1">5. 接口变更时的影响评估 <a class="header-anchor" href="#_5-接口变更时的影响评估" aria-label="Permalink to &quot;5. 接口变更时的影响评估&quot;">​</a></h2><p>当后端 API 发生以下变更时，WebUI 必须跟随更新：</p><ul><li>Public API 白名单接口的成功响应新增必须字段</li><li><code>player_state_projection_spec.md</code> 中正式字段的语义变化</li><li>SSE 事件格式变化（见 <code>player_stream_sse_spec.md</code>）</li></ul><p>当后端发生以下变更时，WebUI <strong>不受影响</strong>（前提是未依赖上述禁止内容）：</p><ul><li>runtime 内部实现调整</li><li>source 插件内部实现调整</li><li>transport 路由策略调整</li><li>兼容字段的删除（<code>cur_music</code>、<code>is_playing</code>、<code>offset</code>、<code>duration</code>）</li></ul><hr><h2 id="_6-相关文档" tabindex="-1">6. 相关文档 <a class="header-anchor" href="#_6-相关文档" aria-label="Permalink to &quot;6. 相关文档&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文档</th><th>职责</th></tr></thead><tbody><tr><td><code>docs/api/api_v1_spec.md</code></td><td>v1 接口完整契约，WebUI 依赖的接口权威来源</td></tr><tr><td><code>docs/spec/player_state_projection_spec.md</code></td><td>播放状态快照字段模型与消费约束</td></tr><tr><td><code>docs/spec/player_stream_sse_spec.md</code></td><td>SSE 推送协议详细规范</td></tr><tr><td><code>docs/architecture/webui_playlist_state.md</code></td><td>playlist selector 的 pending / playback / effective 三层状态模型与 pending-aware 导航语义</td></tr><tr><td><code>docs/spec/webui_playback_state_machine_spec.md</code></td><td>WebUI 消费型状态机规范</td></tr><tr><td><code>docs/spec/webui_playback_state_machine_mapping.md</code></td><td>WebUI 重构实现映射清单</td></tr><tr><td><code>docs/architecture/system_overview.md</code></td><td>WebUI 在系统九个一级边界中的位置</td></tr></tbody></table>',56)]))}const b=a(o,[["render",d]]);export{u as __pageData,b as default};
